fn _csv_parse(src: []const u8) _CsvTable {
    const _pa = std.heap.page_allocator;
    var _rows: std.ArrayList([]const []const u8) = .{};
    var _row:  std.ArrayList([]const u8) = .{};
    var _f:    std.ArrayList(u8) = .{};
